implementation.step:
Add model_validator AFTER all fields are defined. Import: from pydantic import model_validator
from pydantic import ConfigDict, model_validator from pydantic_settings import BaseSettings from pathlib import Path
class Settings(BaseSettings): model_config = ConfigDict(env_file=".env", protected_namespaces=("settings_",))
app_name: str = "Fastener CAD Platform" environment: str = "local" database_url: str = "sqlite:///./storage/app.db" artifact_base_dir: Path = Path("storage/artifacts") raw_asset_base_dir: Path = Path("storage/raw-assets") public_artifact_prefix: str = "/artifacts" public_raw_asset_prefix: str = "/raw-assets" storage_backend: str = "local" s3_bucket: str | None = None redis_url: str | None = None cad_backend: str = "mock" template_version: str = "cadquery-glb-v1" model_sync_generation: bool = True request_id_header: str = "X-Request-ID" cors_allow_origins: str = "http://localhost:5173,http://127.0.0.1:5173" admin_api_key: str | None = None admin_api_key_header: str = "X-Admin-API-Key" auto_create_schema: bool = True require_redis_for_ready: bool = False max_upload_bytes: int = 100 * 1024 * 1024
@property def cors_origins(self) -> list[str]: return [o.strip() for o in self.cors_allow_origins.split(",") if o.strip()]
@model_validator(mode="after") def _validate_production_safety(self) -> "Settings": if self.environment != "production": return self errors: list[str] = [] if self.cad_backend == "mock": errors.append( "CAD_BACKEND=mock is forbidden in production. " "Set CAD_BACKEND=cadquery." ) if self.auto_create_schema: errors.append( "AUTO_CREATE_SCHEMA=true is forbidden in production. " "Run: python -m alembic upgrade head" ) if not self.require_redis_for_ready: errors.append( "REQUIRE_REDIS_FOR_READY=false is forbidden in production. " "Multi-instance deployments will split-brain without Redis." ) if not self.admin_api_key: errors.append( "ADMIN_API_KEY must be set in production. " "Generate with: openssl rand -hex 32" ) if errors: raise ValueError( "Unsafe production configuration:\n" + "\n".join(f" - {e}" for e in errors) ) return self
settings = Settings()
